// Parse Konfig-Tab rows into a config object
const config = {};
try {
  const konfigRows = $input.all();
  for (const row of konfigRows) {
    const key = (row.json['Einstellung'] || row.json['einstellung'] || '').toString().trim();
    const val = (row.json['Wert'] || row.json['wert'] || '').toString().trim();
    if (key) config[key] = val;
  }
} catch (e) {
  throw new Error('Konfig-Tab konnte nicht gelesen werden: ' + e.message);
}

// Validate required fields
if (!config.project_name) throw new Error('project_name fehlt in Konfig-Tab');
if (!config.active_modules) throw new Error('active_modules fehlt in Konfig-Tab');

// Parse active modules
const activeModules = config.active_modules.split(',').map(m => m.trim().toLowerCase());
const activePlatforms = (config.active_platforms || '').split(',').map(p => p.trim().toLowerCase()).filter(p => p);

// Determine which sub-workflows to run
const runWF1 = activeModules.includes('performance');
const runWF2 = activeModules.includes('meta_ads');
const runWF3 = activeModules.includes('competitor');
const runWF4 = activeModules.includes('content');
const runWF5 = activeModules.includes('report');
const runWF6 = activeModules.includes('report'); // WF6 runs whenever WF5 runs

// Calendar week calculation
const now = new Date();
const year = now.getFullYear();
const jan1 = new Date(year, 0, 1);
const days = Math.floor((now - jan1) / (24 * 60 * 60 * 1000));
const calendarWeek = Math.ceil((days + jan1.getDay() + 1) / 7);

// Base URL for sub-workflow webhooks
const baseUrl = 'https://meinoffice.app.n8n.cloud/webhook-test';

// Build config payload to send to sub-workflows
const configPayload = {
  project_name: config.project_name,
  brand_name: config.brand_name || config.project_name,
  brand_description: config.brand_description || '',
  brand_tone: config.brand_tone || 'professionell',
  brand_colors: config.brand_colors || '#1a73e8, #ffffff',
  active_platforms: activePlatforms,
  report_recipients: config.report_recipients || '',
  report_cc: config.report_cc || '',
  report_language: config.report_language || 'de',
  apify_rate_limit_ms: parseInt(config.apify_rate_limit_ms || '5000', 10),
  apify_max_concurrent: parseInt(config.apify_max_concurrent || '2', 10)
};

const startedAt = new Date().toISOString();

return [{
  json: {
    config: configPayload,
    modules: {
      wf1: runWF1,
      wf2: runWF2,
      wf3: runWF3,
      wf4: runWF4,
      wf5: runWF5,
      wf6: runWF6
    },
    calendarWeek,
    year,
    startedAt,
    baseUrl,
    activeModules,
    activePlatforms
  }
}];

// Evaluate Wave 1 results (WF1, WF2, WF3)
const configData = $('Konfig verarbeiten').first().json;
const modules = configData.modules;

// Collect results from Wave 1 sub-workflows
const wave1Items = $input.all();
const wave1Results = [];
const wave1Errors = [];

// Map the 3 items to their respective workflows
// Item order from Merge (append): WF1 (input 0), WF2 (input 1), WF3 (input 2)
const wfNames = ['WF1 Performance Collector', 'WF2 Meta Ads Analyzer', 'WF3 Competitor Monitor'];
const wfKeys = ['wf1', 'wf2', 'wf3'];
const wfModuleActive = [modules.wf1, modules.wf2, modules.wf3];

for (let i = 0; i < wave1Items.length; i++) {
  const item = wave1Items[i].json;
  const wfKey = wfKeys[i] || 'unknown';
  const wfName = wfNames[i] || 'Unknown';
  const isActive = wfModuleActive[i] !== false;

  if (!isActive) {
    wave1Results.push({
      workflow: wfName,
      key: wfKey,
      status: 'skipped',
      message: 'Modul nicht aktiv in Konfig'
    });
    continue;
  }

  // Check if the HTTP request itself failed (error in response)
  if (item.error || item.statusCode >= 400) {
    wave1Errors.push({
      workflow: wfName,
      key: wfKey,
      status: 'error',
      message: item.error || item.message || ('HTTP ' + (item.statusCode || 'unknown')),
      details: item
    });
    continue;
  }

  // Check the sub-workflow's structured response
  if (item.success === false) {
    wave1Errors.push({
      workflow: wfName,
      key: wfKey,
      status: 'error',
      message: 'Sub-Workflow meldete Fehler',
      errors: item.errors
    });
    continue;
  }

  wave1Results.push({
    workflow: wfName,
    key: wfKey,
    status: item.success ? 'success' : 'partial_success',
    data: item.data || null
  });
}

const wave1Success = wave1Results.filter(r => r.status === 'success' || r.status === 'partial_success').length;
const wave1Failed = wave1Errors.length;
const wave1Ok = wave1Success > 0;

return [{
  json: {
    config: configData.config,
    modules: configData.modules,
    calendarWeek: configData.calendarWeek,
    year: configData.year,
    startedAt: configData.startedAt,
    baseUrl: configData.baseUrl,
    wave1: {
      results: wave1Results,
      errors: wave1Errors,
      successCount: wave1Success,
      errorCount: wave1Failed,
      ok: wave1Ok
    },
    runLog: [
      ...wave1Results.map(r => ({ wave: 1, workflow: r.workflow, status: r.status })),
      ...wave1Errors.map(e => ({ wave: 1, workflow: e.workflow, status: 'error', message: e.message }))
    ]
  }
}];

// Wave 1 completely failed -- skip Waves 2-4
const data = $input.first().json;

data.runLog.push({
  wave: 'skip',
  workflow: 'WF4/WF5/WF6',
  status: 'skipped',
  message: 'Uebersprungen weil Wave-1 komplett fehlgeschlagen'
});

data.finalStatus = 'error';
data.finalMessage = 'Wave-1 komplett fehlgeschlagen. Keine Daten fuer Content/Report.';

return [{ json: data }];

// Evaluate Wave 2 result (WF4 Content Creator)
const prevData = $('Wave-1 auswerten').first().json;
const wf4Result = $input.first().json;
const modules = prevData.modules;

let wave2Entry;

if (!modules.wf4) {
  wave2Entry = { wave: 2, workflow: 'WF4 Content Creator', status: 'skipped', message: 'Modul nicht aktiv' };
} else if (wf4Result.error || wf4Result.statusCode >= 400) {
  wave2Entry = { wave: 2, workflow: 'WF4 Content Creator', status: 'error', message: wf4Result.error || wf4Result.message || 'HTTP Fehler' };
} else if (wf4Result.success === false) {
  wave2Entry = { wave: 2, workflow: 'WF4 Content Creator', status: 'error', message: 'Sub-WF meldete Fehler', errors: wf4Result.errors };
} else {
  wave2Entry = { wave: 2, workflow: 'WF4 Content Creator', status: 'success' };
}

prevData.runLog.push(wave2Entry);
prevData.wave2 = { result: wave2Entry, ok: wave2Entry.status === 'success' || wave2Entry.status === 'skipped' };

return [{ json: prevData }];

// Evaluate Wave 3 result (WF5 Report Generator)
const prevData = $('Wave-2 auswerten').first().json;
const wf5Result = $input.first().json;
const modules = prevData.modules;

let wave3Entry;
let reportData = null;

if (!modules.wf5) {
  wave3Entry = { wave: 3, workflow: 'WF5 Report Generator', status: 'skipped', message: 'Report-Modul nicht aktiv' };
} else if (wf5Result.error || wf5Result.statusCode >= 400) {
  wave3Entry = { wave: 3, workflow: 'WF5 Report Generator', status: 'error', message: wf5Result.error || wf5Result.message || 'HTTP Fehler' };
} else if (wf5Result.success === false) {
  wave3Entry = { wave: 3, workflow: 'WF5 Report Generator', status: 'error', message: 'Sub-WF meldete Fehler', errors: wf5Result.errors };
} else {
  wave3Entry = { wave: 3, workflow: 'WF5 Report Generator', status: 'success' };
  reportData = wf5Result.data || null;
}

prevData.runLog.push(wave3Entry);
prevData.wave3 = { result: wave3Entry, ok: wave3Entry.status === 'success', reportData };

return [{ json: prevData }];

// Evaluate Wave 4 result (WF6 Report Sender)
const prevData = $('Wave-3 auswerten').first().json;
const wf6Result = $input.first().json;

let wave4Entry;

if (wf6Result.error || wf6Result.statusCode >= 400) {
  wave4Entry = { wave: 4, workflow: 'WF6 Report Sender', status: 'error', message: wf6Result.error || wf6Result.message || 'HTTP Fehler' };
} else if (wf6Result.success === false) {
  wave4Entry = { wave: 4, workflow: 'WF6 Report Sender', status: 'error', message: 'Sub-WF meldete Fehler', errors: wf6Result.errors };
} else {
  wave4Entry = { wave: 4, workflow: 'WF6 Report Sender', status: 'success' };
}

prevData.runLog.push(wave4Entry);
prevData.wave4 = { result: wave4Entry, ok: wave4Entry.status === 'success' };

return [{ json: prevData }];

// Report was not generated -- skip WF6
const data = $input.first().json;

data.runLog.push({
  wave: 4,
  workflow: 'WF6 Report Sender',
  status: 'skipped',
  message: 'Uebersprungen weil Report nicht erstellt wurde'
});

data.wave4 = { result: { status: 'skipped' }, ok: false };

return [{ json: data }];

// Build final run log from whichever path completed
let data;

// Try to get data from the different possible paths
try { data = $('Wave-4 auswerten').first().json; } catch(e) {}
if (!data) { try { data = $('Report uebersprungen').first().json; } catch(e) {} }
if (!data) { try { data = $('Wave-1 komplett fehlgeschlagen').first().json; } catch(e) {} }

if (!data) {
  return [{ json: { error: 'Keine Daten von Sub-Workflows erhalten', runLog: [], finalStatus: 'error' } }];
}

const finishedAt = new Date().toISOString();
const startMs = new Date(data.startedAt).getTime();
const endMs = new Date(finishedAt).getTime();
const durationSeconds = Math.round((endMs - startMs) / 1000 * 100) / 100;

// Count successes and errors
const runLog = data.runLog || [];
const successWFs = runLog.filter(r => r.status === 'success').map(r => r.workflow);
const errorWFs = runLog.filter(r => r.status === 'error').map(r => r.workflow);
const skippedWFs = runLog.filter(r => r.status === 'skipped').map(r => r.workflow);

let finalStatus;
if (data.finalStatus) {
  finalStatus = data.finalStatus;
} else if (errorWFs.length === 0) {
  finalStatus = 'success';
} else if (successWFs.length > 0) {
  finalStatus = 'partial_success';
} else {
  finalStatus = 'error';
}

return [{
  json: {
    workflow_name: 'WF7 SocialPulse Controller',
    workflow_id: $workflow.id || '',
    execution_id: $execution.id || '',
    project_name: data.config?.project_name || 'unknown',
    started_at: data.startedAt,
    finished_at: finishedAt,
    duration_seconds: durationSeconds,
    status: finalStatus,
    platforms_ok: successWFs,
    platforms_error: errorWFs,
    error_details: errorWFs.length > 0 ? JSON.stringify(runLog.filter(r => r.status === 'error')) : null,
    items_processed: successWFs.length + skippedWFs.length + errorWFs.length,
    notes: 'Waves: W1=' + (data.wave1?.successCount || 0) + '/' + ((data.wave1?.successCount || 0) + (data.wave1?.errorCount || 0)) + ' OK, W2=' + (data.wave2?.result?.status || 'n/a') + ', W3=' + (data.wave3?.result?.status || 'n/a') + ', W4=' + (data.wave4?.result?.status || 'n/a'),
    // Pass full data for downstream nodes
    _config: data.config,
    _runLog: runLog,
    _calendarWeek: data.calendarWeek,
    _year: data.year,
    _finalMessage: data.finalMessage || '',
    _wave1: data.wave1,
    _wave2: data.wave2,
    _wave3: data.wave3,
    _wave4: data.wave4
  }
}];

// Build comprehensive final response
const runLogData = $('Finales Run-Log zusammenbauen').first().json;

const response = {
  success: runLogData.status === 'success',
  workflow: 'WF7 SocialPulse Controller',
  status: runLogData.status,
  summary: {
    projectName: runLogData.project_name,
    calendarWeek: runLogData._calendarWeek,
    year: runLogData._year,
    durationSeconds: runLogData.duration_seconds,
    startedAt: runLogData.started_at,
    finishedAt: runLogData.finished_at
  },
  waves: {
    wave1: {
      workflows: ['WF1', 'WF2', 'WF3'],
      successCount: runLogData._wave1?.successCount || 0,
      errorCount: runLogData._wave1?.errorCount || 0,
      ok: runLogData._wave1?.ok || false
    },
    wave2: {
      workflow: 'WF4',
      status: runLogData._wave2?.result?.status || 'not_run'
    },
    wave3: {
      workflow: 'WF5',
      status: runLogData._wave3?.result?.status || 'not_run'
    },
    wave4: {
      workflow: 'WF6',
      status: runLogData._wave4?.result?.status || 'not_run'
    }
  },
  runLog: runLogData._runLog || [],
  errors: (runLogData._runLog || []).filter(r => r.status === 'error').length > 0
    ? (runLogData._runLog || []).filter(r => r.status === 'error')
    : null,
  message: runLogData._finalMessage || (runLogData.status === 'success'
    ? 'Alle Workflows erfolgreich abgeschlossen.'
    : runLogData.status === 'partial_success'
      ? 'Teilweise erfolgreich. Einige Workflows hatten Fehler.'
      : 'Pipeline fehlgeschlagen. Details im runLog.'),
  timestamp: new Date().toISOString()
};

return [{ json: response }];
